 .execute(&pool)
 .await;

 //routing
 let app = Router::new()
 .route("/", get(root))
 .route(
 "/api/products/",
 get(handlers::get\_products).post(handlers::create\_product),
 )
 .with\_state(pool)
 .layer(cors);

 tracing::debug!("listening on {}", "0.0.0.0:3000");
 println!(" Listening on port {}", "0.0.0.0:3000");
 axum::Server::bind(&"0.0.0.0:3000".parse().unwrap())
 .serve(app.into\_make\_service())
 .await
 .unwrap();
}

