public class TwitchWebsocket : MonoBehaviour
{
 private WebSocket webSocket;

 private async void Start()
 {
 webSocket = new WebSocket("wss://eventsub-beta.wss.twitch.tv/ws");

 webSocket.OnOpen += OnWebSocketOpen;
 webSocket.OnMessage += OnWebSocketMessage;
 webSocket.OnError += OnWebSocketError;
 webSocket.OnClose += OnWebSocketClose;

 await webSocket.Connect();
 }

 private void OnWebSocketOpen()
 {
 Debug.Log("WebSocket opened.");

 // Send the standard WebSocket Ping frame.
 webSocket.Send(new byte[] { 9 });
 }

 private void OnWebSocketMessage(byte[] bytes)
 {
 string message = System.Text.Encoding.UTF8.GetString(bytes);
 Debug.Log("WebSocket message received: " + message);

 if (message.Contains("Welcome"))
 {
 Debug.Log("Received welcome message from Twitch.");
 TwitchSessionWelcome welcome = JsonUtility.FromJson(message);
 }
 }

 private void OnWebSocketError(string error)
 {
 Debug.LogError("WebSocket error: " + error);
 }

 private void OnWebSocketClose(WebSocketCloseCode closeCode)
 {
 Debug.Log("WebSocket closed with code " + closeCode);
 }

 private void Update()
 {
 webSocket.DispatchMessageQueue();
 }

 private async void OnDestroy()
 {
 await webSocket.Close();
 }

