\_REQUEST\_CACHE: RequestCache
class RequestCache:
 """
 Interface for managing a per-thread loader cache for a request.

 """

 def get(self) -> dict[type[Loadable], Loader]:
 raise NotImplementedError

 def set(self, loader\_cache: dict[type[Loadable], Loader]) -> None:
 raise NotImplementedError

 def purge(self) -> None:
 raise NotImplementedError

 def context(self, loader\_cache: dict[type[Loadable], Loader]) -> 'RequestCache.ContextManager':
 return RequestCache.ContextManager(
 request\_cache=self,
 loader\_cache=loader\_cache,
 )

 @attr.s(auto\_attribs=True, kw\_only=True, frozen=True)
 class ContextManager:
 request\_cache: RequestCache
 loader\_cache: dict[type[Loadable], Loader]

 def \_\_enter\_\_(self):
 assert not self.request\_cache.get()
 self.request\_cache.set(self.loader\_cache)

 def \_\_exit\_\_(self, exc\_type, exc\_val, exc\_tb):
 self.request\_cache.purge()
def purge() -> None:
 \_REQUEST\_CACHE.purge()
def purge\_cache(fn: T) -> T:
 def decorator(\*args, \*\*kwargs):
 try:
 return fn(\*args, \*\*kwargs)
 finally:
 purge()

 return decorator
def register\_request\_cache(cls: type[RequestCache]):
 global \_REQUEST\_CACHE
 \_REQUEST\_CACHE = cls()
 return cls
